@namespace Lumeo

<nav role="navigation" aria-label="pagination" class="@CssClass" @attributes="AdditionalAttributes">
    @if (IsDataDriven)
    {
        <ul class="flex flex-row items-center gap-1">
            <li>
                <button type="button" class="@NavButtonClass" aria-label="Go to previous page"
                        disabled="@(CurrentPage <= 1)" @onclick="() => GoTo(CurrentPage - 1)">
                    <SvgGlyph Svg="@(LumeoIcons.ChevronLeft)" class="h-4 w-4" />
                </button>
            </li>
            @foreach (var item in PageSequence)
            {
                @if (item == EllipsisMarker)
                {
                    <PaginationEllipsis />
                }
                else
                {
                    var page = item;
                    var pageLabel = $"Go to page {page}";
                    <PaginationItem IsActive="@(page == CurrentPage)"
                                    aria-label="@pageLabel"
                                    OnClick="@(() => GoTo(page))">@(page)</PaginationItem>
                }
            }
            <li>
                <button type="button" class="@NavButtonClass" aria-label="Go to next page"
                        disabled="@(CurrentPage >= EffectiveTotalPages)" @onclick="() => GoTo(CurrentPage + 1)">
                    <SvgGlyph Svg="@(LumeoIcons.ChevronRight)" class="h-4 w-4" />
                </button>
            </li>
        </ul>
    }
    else
    {
        @ChildContent
    }
</nav>

@code {
    /// <summary>Fully compositional content (<see cref="PaginationContent"/>,
    /// <see cref="PaginationItem"/>, etc.). When set, data-driven mode is disabled
    /// and this content renders verbatim instead.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }

    // --- Data-driven mode (#210) — opt-in. Supply Page plus either TotalPages
    // or TotalItems (+ PageSize); the pager then renders prev/next, boundary and
    // sibling page buttons with ellipsis automatically. When ChildContent is set
    // the component stays fully compositional (unchanged). ---
    /// <summary>The current 1-based page. Setting this (without <see cref="ChildContent"/>)
    /// enables data-driven mode, which auto-renders prev/next and numbered page buttons.</summary>
    [Parameter] public int? Page { get; set; }
    /// <summary>Fired with the newly clamped page number when the user clicks a page,
    /// prev/next button, or when a shrunk total forces the current page back in range.</summary>
    [Parameter] public EventCallback<int> PageChanged { get; set; }
    /// <summary>Total number of pages, for data-driven mode. Takes precedence over
    /// <see cref="TotalItems"/>/<see cref="PageSize"/> when both are supplied.</summary>
    [Parameter] public int? TotalPages { get; set; }
    /// <summary>Total item count, for data-driven mode; combined with <see cref="PageSize"/>
    /// to compute the page count when <see cref="TotalPages"/> is not set directly.</summary>
    [Parameter] public int? TotalItems { get; set; }
    /// <summary>Items per page, used with <see cref="TotalItems"/> to compute the total page
    /// count in data-driven mode. Defaults to 10.</summary>
    [Parameter] public int PageSize { get; set; } = 10;
    /// <summary>Pages shown on each side of the current page (default 1).</summary>
    [Parameter] public int SiblingCount { get; set; } = 1;
    /// <summary>Pages always shown at the very start/end (default 1).</summary>
    [Parameter] public int BoundaryCount { get; set; } = 1;

    /// <summary>Additional CSS classes merged onto the root <c>nav</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the root <c>nav</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private const int EllipsisMarker = -1;

    private string CssClass => Cx.Merge("mx-auto flex w-full justify-center", Class);

    private int EffectiveTotalPages =>
        TotalPages ?? (TotalItems is int t && PageSize > 0 ? Math.Max(1, (int)Math.Ceiling(t / (double)PageSize)) : 0);

    private bool IsDataDriven => ChildContent is null && Page is not null && EffectiveTotalPages > 0;

    private int CurrentPage => Math.Clamp(Page ?? 1, 1, Math.Max(1, EffectiveTotalPages));

    private bool _reconciling;

    // Reconcile a shrunk TotalItems/TotalPages back to the parent. In data-driven
    // mode the render clamps Page for display, but the controlled Page held by the
    // parent would otherwise stay out of range forever; push the clamped value via
    // PageChanged so Page, the fetched data and the highlight stay in sync (#42).
    protected override async Task OnParametersSetAsync()
    {
        if (_reconciling) return;
        if (ChildContent is not null || Page is null) return;

        var total = EffectiveTotalPages;
        if (total <= 0) return;

        var requested = Page.Value;
        var clamped = Math.Clamp(requested, 1, total);
        if (clamped == requested) return;

        _reconciling = true;
        try
        {
            await PageChanged.InvokeAsync(clamped);
        }
        finally
        {
            _reconciling = false;
        }
    }

    private string NavButtonClass =>
        "inline-flex h-11 w-11 sm:h-9 sm:w-9 items-center justify-center rounded-md text-sm font-medium cursor-pointer transition-colors hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 disabled:pointer-events-none disabled:opacity-50";

    private async Task GoTo(int page)
    {
        var clamped = Math.Clamp(page, 1, EffectiveTotalPages);
        if (clamped != CurrentPage)
            await PageChanged.InvokeAsync(clamped);
    }

    // Page sequence with ellipsis markers (-1). Always shows first/last + the
    // boundary band + a sibling band around the current page; gaps collapse to
    // a single ellipsis.
    private IReadOnlyList<int> PageSequence
    {
        get
        {
            int total = EffectiveTotalPages;
            var result = new List<int>();
            if (total <= 0) return result;

            int current = CurrentPage;
            int boundary = Math.Max(0, BoundaryCount);
            int sibling = Math.Max(0, SiblingCount);

            var pages = new SortedSet<int> { 1, total, current };
            for (int i = 1; i <= Math.Min(boundary, total); i++) pages.Add(i);
            for (int i = Math.Max(total - boundary + 1, 1); i <= total; i++) pages.Add(i);
            for (int i = current - sibling; i <= current + sibling; i++)
                if (i >= 1 && i <= total) pages.Add(i);

            int prev = 0;
            foreach (var p in pages)
            {
                if (prev != 0 && p - prev > 1) result.Add(EllipsisMarker);
                result.Add(p);
                prev = p;
            }
            return result;
        }
    }
}

@namespace Lumeo

<ul class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</ul>

@code {
    /// <summary>The pagination items (<see cref="PaginationItem"/>, prev/next,
    /// <see cref="PaginationEllipsis"/>) rendered as an ordered list of buttons.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Additional CSS classes merged onto the root <c>ul</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the root <c>ul</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("flex flex-row items-center gap-1", Class);
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<li>
    <span class="@CssClass" @attributes="AdditionalAttributes">
        <SvgGlyph Svg="@(LumeoIcons.Ellipsis)" class="h-4 w-4" />
        <span class="sr-only">@L["Pagination.MorePages"]</span>
    </span>
</li>

@code {
    [CascadingParameter] private Lumeo.Density? Density { get; set; }
    /// <summary>Additional CSS classes merged onto the ellipsis <c>span</c>.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the ellipsis <c>span</c>.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Tracks the ambient DensityScope so the ellipsis aligns with the page
    // cells; Comfortable reproduces the historical `h-9 w-9`.
    private string SizeClass => Density switch
    {
        Lumeo.Density.Compact => "h-8 w-8",
        Lumeo.Density.Spacious => "h-10 w-10",
        _ => "h-9 w-9"
    };

    private string CssClass => Cx.Merge("flex", SizeClass, "items-center justify-center", Class);
}

@namespace Lumeo

<li>
    <button type="button" class="@CssClass" aria-current="@(IsActive ? "page" : null)" @onclick="OnClick" @attributes="AdditionalAttributes">
        @ChildContent
    </button>
</li>

@code {
    /// <summary>The page number's visible label.</summary>
    [Parameter] public RenderFragment? ChildContent { get; set; }
    /// <summary>Marks this item as the current page: styles it with a bordered/shadowed
    /// look and sets <c>aria-current="page"</c>.</summary>
    [Parameter] public bool IsActive { get; set; }
    /// <summary>Fired when the button is clicked.</summary>
    [Parameter] public EventCallback OnClick { get; set; }
    [CascadingParameter] private Lumeo.Density? Density { get; set; }
    /// <summary>Additional CSS classes merged onto the button.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the button.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Desktop cell size tracks the ambient DensityScope; the mobile touch
    // floor (h-11 w-11) is kept so pages stay tappable. Comfortable
    // reproduces the historical `sm:h-9 sm:w-9`.
    private string SizeClass => Density switch
    {
        Lumeo.Density.Compact => "h-11 w-11 sm:h-8 sm:w-8",
        Lumeo.Density.Spacious => "h-11 w-11 sm:h-10 sm:w-10",
        _ => "h-11 w-11 sm:h-9 sm:w-9"
    };

    private string CssClass => Cx.Merge("inline-flex items-center justify-center whitespace-nowrap rounded-md text-sm font-medium cursor-pointer transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2", SizeClass, (IsActive ? "border border-input bg-background shadow-sm" : "hover:bg-accent hover:text-accent-foreground"), Class);
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<li>
    <button type="button" class="@CssClass" @onclick="OnClick" disabled="@Disabled" aria-label="@L["Pagination.Next"]" @attributes="AdditionalAttributes">
        <span>@L["Pagination.Next"]</span>
        <SvgGlyph Svg="@(LumeoIcons.ChevronRight)" class="h-4 w-4 [dir=rtl]:rotate-180" />
    </button>
</li>

@code {
    /// <summary>Fired when the button is clicked.</summary>
    [Parameter] public EventCallback OnClick { get; set; }
    /// <summary>Disables the button, e.g. when already on the last page.</summary>
    [Parameter] public bool Disabled { get; set; }
    [CascadingParameter] private Lumeo.Density? Density { get; set; }
    /// <summary>Additional CSS classes merged onto the button.</summary>
    [Parameter] public string? Class { get; set; }
    /// <summary>Unmatched attributes splatted onto the button.</summary>
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // Desktop height + horizontal padding track the ambient DensityScope; the
    // mobile touch floor (h-11) is kept. Comfortable reproduces `sm:h-9 px-3`.
    private string SizeClass => Density switch
    {
        Lumeo.Density.Compact => "h-11 sm:h-8 px-2.5",
        Lumeo.Density.Spacious => "h-11 sm:h-10 px-4",
        _ => "h-11 sm:h-9 px-3"
    };

    private string CssClass => Cx.Merge("inline-flex items-center justify-center gap-1 whitespace-nowrap rounded-md text-sm font-medium transition-colors hover:bg-accent hover:text-accent-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-2", SizeClass, "disabled:pointer-events-none disabled:opacity-50", Class);
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<li>
    <button type="button" class="@CssClass" @onclick="OnClick" disabled="@Disabled" aria-label="@L["Pagination.Previous"]" @attributes="AdditionalAttributes">
